/* OpenLieroX Wiki - client-side helpers for the static re-creation.
 *
 * The original wiki relied on MediaWiki's server side for search and the
 * "Random page" link. On a static site we reproduce both with a small JSON
 * index generated by Jekyll (search-index.json).
 */
(function () {
	"use strict";

	// <html> knows the deployment base path via the stylesheet href.
	function baseUrl() {
		var link = document.querySelector('link[rel="stylesheet"]');
		if (link) {
			var href = link.getAttribute("href");
			return href.replace(/\/assets\/css\/style\.css.*$/, "");
		}
		return "";
	}

	var BASE = baseUrl();
	var INDEX_URL = BASE + "/search-index.json";
	var indexPromise = null;

	function loadIndex() {
		if (!indexPromise) {
			indexPromise = fetch(INDEX_URL).then(function (r) {
				return r.json();
			});
		}
		return indexPromise;
	}

	function qs(name) {
		var m = new RegExp("[?&]" + name + "=([^&]*)").exec(location.search);
		return m ? decodeURIComponent(m[1].replace(/\+/g, " ")) : "";
	}

	/* --- "Random page" -------------------------------------------------- */
	function goRandom(ev) {
		if (ev) ev.preventDefault();
		loadIndex().then(function (pages) {
			var pool = pages.filter(function (p) {
				return p.url.indexOf("/Special_") === -1;
			});
			if (!pool.length) return;
			var pick = pool[Math.floor(Math.random() * pool.length)];
			location.href = pick.url;
		});
	}

	/* --- Search --------------------------------------------------------- */
	function escapeHtml(s) {
		return s.replace(/[&<>"]/g, function (c) {
			return { "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c];
		});
	}

	function snippet(text, terms) {
		var lower = text.toLowerCase();
		var at = -1;
		for (var i = 0; i < terms.length; i++) {
			at = lower.indexOf(terms[i]);
			if (at !== -1) break;
		}
		if (at === -1) at = 0;
		var start = Math.max(0, at - 60);
		var piece = text.substr(start, 250);
		if (start > 0) piece = "..." + piece;
		piece = escapeHtml(piece);
		terms.forEach(function (t) {
			if (!t) return;
			piece = piece.replace(
				new RegExp("(" + t.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")", "ig"),
				"<strong class='searchmatch'>$1</strong>"
			);
		});
		return piece;
	}

	function runSearch(container) {
		var query = qs("search").trim();
		var box = document.getElementById("searchInput");
		if (box && query) box.value = query;
		if (!query) {
			container.innerHTML =
				"<p class='search-empty'>Enter a search term in the box at the top of the page.</p>";
			return;
		}
		container.innerHTML = "<p>Searching for <strong>" + escapeHtml(query) + "</strong>...</p>";
		var terms = query.toLowerCase().split(/\s+/);
		loadIndex().then(function (pages) {
			var hits = [];
			pages.forEach(function (p) {
				if (p.url.indexOf("/Special_") !== -1) return;
				var hay = (p.title + " " + p.text).toLowerCase();
				var score = 0;
				terms.forEach(function (t) {
					if (!t) return;
					if (p.title.toLowerCase().indexOf(t) !== -1) score += 10;
					var idx = hay.indexOf(t);
					while (idx !== -1) {
						score += 1;
						idx = hay.indexOf(t, idx + 1);
					}
				});
				if (score > 0) hits.push({ page: p, score: score });
			});
			hits.sort(function (a, b) {
				return b.score - a.score;
			});
			if (!hits.length) {
				container.innerHTML =
					"<p>There were no results matching <strong>" +
					escapeHtml(query) +
					"</strong>.</p>";
				return;
			}
			var html =
				"<p>Results <strong>1-" +
				hits.length +
				"</strong> for <strong>" +
				escapeHtml(query) +
				"</strong>.</p><ul class='searchresults'>";
			hits.forEach(function (h) {
				html +=
					"<li><a href='" +
					h.page.url +
					"'>" +
					escapeHtml(h.page.title) +
					"</a><br /><span class='searchsnippet'>" +
					snippet(h.page.text, terms) +
					"</span></li>";
			});
			html += "</ul>";
			container.innerHTML = html;
		});
	}

	/* --- Wire everything up on load ------------------------------------- */
	document.addEventListener("DOMContentLoaded", function () {
		var rnd = document.getElementById("n-randompage");
		if (rnd) rnd.addEventListener("click", goRandom);

		var results = document.getElementById("search-results-container");
		if (results) runSearch(results);

		if (document.getElementById("random-redirect")) goRandom();
	});
})();
